module.render:
    const lt = (args.layout || 'updown').toLowerCase();
    const layout = lt === 'right' ? 'right' : lt === 'lines' ? 'lines' : 'updown';
    const color = args.color || 'var(--accent-color)';
    const fontSize = args.fontSize || '0.9em';
    const gap = (args.gap || '10px').trim() || '10px';
    const radius = (args.radius || '8px').trim() || '8px';
    const filled = String(args.filled) !== 'false';
    const label = (sections[0] || '').trim();
    const kids = sections.slice(1).map((s) => s.trim()).filter(Boolean);
    // A child that already rendered as a tree-box is a SUBTREE (pass it through);
    // anything else is a LEAF (wrap in a box). Each child is then wrapped in a real
    // `.mdp-tree-slot` element — needed for the `lines` layout's CSS connectors,
    // because the module's own display:contents wrapper can't host pseudo-elements.
    // Raw Markdown labels render via the single document markdown pass (blank lines).
    const kidHtml = kids.map((c) => {
      const inner = /class="[^"]*mdp-tree-box/.test(c)
        ? c
        : `

<div class="mdp-tree-box mdp-tree-leaf">

<div class="mdp-tree-label">

${c}

</div>

</div>

`;
      return `

<div class="mdp-tree-slot">

${inner}

</div>

`;
    }).join('
');
    const kidsWrap = kids.length ? `

<div class="mdp-tree-kids">

${kidHtml}

</div>

` : '';
    const cls = `mdp-tree-box mdp-tree-${layout} ${kids.length ? 'mdp-tree-branch' : 'mdp-tree-leaf'}${filled ? '' : ' mdp-tree-nofill'}`;
    return `

<div class="${cls}" style="--tree-color:${color}; --tree-font:${fontSize}; --tree-gap:${gap}; --tree-radius:${radius};">

<div class="mdp-tree-label">

${label}

</div>

${kidsWrap}</div>

`;
